<template>
    <div class="family-node">
        <div class="companion"
             :class="{more:node.spouse.length>1,noSpouse:node.spouse.length===0,noChildren:node.children.length===0,noParent:node.parent===''}"
             :style="'width:'+fullWidth+'px;--spouseNum:'+node.spouse.length">
            <template v-if="parent.children">
                <div @click="$emit('toolMenu', node)" v-if="node!=null" class="node"
                     :class="{ 'first':checkIndex(node,familyTree)===0,'last':checkIndex(node,familyTree)===parent.children.length-1,'death': node.deathDate != ''&&node.deathDate != null,'male': node.gender === 'male', 'female': node.gender === 'female' }">
                    <div class="node-content">
                        <i class="tx" v-if="node.photo"><img :src="node.photo"></i>
                        <i class="el-icon-user-solid" v-else></i>
                        <span>{{ node.name }}</span>
                    </div>
                </div>
            </template>
            <template v-else>
                <div @click="$emit('toolMenu', node)" v-if="node!=null" class="node"
                     :class="{ 'first':checkIndex(node,familyTree)===0,'death': node.deathDate != ''&&node.deathDate != null,'male': node.gender === 'male', 'female': node.gender === 'female' }">
                    <div class="node-content">
                        <i class="tx" v-if="node.photo"><img :src="node.photo"></i>
                        <i class="el-icon-user-solid" v-else></i>
                        <span>{{ node.name }}</span>
                    </div>
                </div>
            </template>
            <div class="spouses">
                <div v-for="sp in node.spouse" @click="$emit('toolMenuS', sp)" class="node"
                     :class="{ 'death': sp.deathDate != ''&&sp.deathDate != null,'male': sp.gender === 'male', 'female': sp.gender === 'female' }">
                    <div class="node-content">
                        <i class="tx" v-if="sp.photo"><img :src="sp.photo"></i>
                        <i class="el-icon-user-solid" v-else></i>
                        <span>{{ sp.name }}</span>
                    </div>
                </div>
            </div>
        </div>
        <div v-if="node!=null&&node.children.length>0" class="children">

            <family-node
                    v-for="child in node.children"
                    :key="child.id"
                    :id="id"
                    :node="child"
                    @toolMenu="$emit('toolMenu', $event)"
                    @toolMenuS="$emit('toolMenuS',$event)"
            />

        </div>
    </div>
</template>

<script>
    export default {
        name: 'FamilyNode',
        data() {
            return {
                familyTree: {},
                parent: {}
            }
        },
        props: {
            node: {
                type: Object,
                default() {
                    return {}
                }
            },
            id: {
                type: String,
                default: ''
            },
        },
        created() {

        },
        mounted() {
            //this.$el.style.cssText = '--numSpouse:'+(this.$el.scrollWidth/40)+';--wf:' + this.$el.scrollWidth + 'px;--hf:' + this.$el.scrollHeight
            this.$el.style.cssText = '--wf:' + this.$el.scrollWidth + 'px;--hf:' + this.$el.scrollHeight
            this.familyTree = this.$root.$children[0].$children[0].familyTree


        },
        computed: {
            fullWidth() {
                let w = 40
                return (w * (this.node.spouse.length + 1))

            }
        },
        methods: {
            findNodeById(tree, id) {
                if (tree.id === id) {
                    return tree; // 找到匹配的节点，返回它
                } else if (tree.children) { // 检查是否有子节点
                    for (let child of tree.children) {
                        const result = this.findNodeById(child, id); // 递归搜索子节点
                        if (result) {
                            return result; // 如果在子节点中找到，返回该节点
                        }
                    }
                }
                return null; // 没有找到匹配的节点
            },
            checkIndex(node, data) {
                if (data.id) {
                    if (node.parent) {
                        let fi = this.findNodeById(data, node.parent)
                        this.parent = fi
                        const index = fi.children.indexOf(node)

                        return index
                    } else {
                        return 0
                    }
                }

            },
            measureWidth(node) {
                if (node.children.length + node.spouse.length === 1) {
                    return 0
                } else {
                    return '100%'
                }
            },
            measureWidthA(node) {
                let w
                if (node.children.length === 1) {
                    w = (node.spouse.length - 1) * 20
                } else {
                    let fw = (node.spouse.length + 1) * 40//240
                    let cw = node.children.length * 40 + (node.children.length - 1) * 15//150
                    let last = fw - (fw - cw) * 0.5
                    w = last - 60
                    //w=(node.spouse.length+1)*40-(node.children.length*40+(node.children.length-1)*15)
                }
                return w + 'px'
            }
        },
    }
</script>

<style scoped>

    .family-node {
        display: flex;
        flex-direction: column;
        align-items: center;
        position: relative;
        gap: 40px;
    }

    .family-node:has( > .more) {
        align-items: flex-start;
    }

    .companion {
        position: relative;
    }

    .companion:before {
        content: '';
        position: absolute;
        top: -20px;
        left: 20px;
        width: 1px;
        height: 20px;
        background-color: var(--line);
    }

    .companion:after {
        content: '';
        position: absolute;
        top: 95px;
        left: 40px;
        width: 1px;
        height: 25px;
        background-color: var(--line);
    }

    .companion.noParent:before {
        content: none;
    }

    .companion.noChildren:after {
        content: none;
    }

    .companion.noSpouse:after, .companion.more:after {
        left: 20px;
        top: 100px;
        height: 20px;
    }


    .spouses {
        position: absolute;
        top: 0;
        transform: translateX(40px);
        display: flex;

    }

    .node {
        width: 40px;
        height: 100px;
        border-radius: 8px;
        cursor: pointer;
        position: relative;
        transition: all .4s;
    }

    .node:hover {
        transform: scale(1.1);
    }

    .node.first:before {
        content: '';
        width: calc(var(--wf) * 0.5);
        height: 20px;
        background: var(--bg);
        position: absolute;
        transform: translate(-19px, -21px);
        right: 0;
    }

    .node.last:before {
        content: '';
        width: calc(var(--wf) - 20px);
        height: 20px;
        background: var(--bg);
        position: absolute;
        transform: translate(20px, -21px);
        left: 0;
    }

    .node.first.last:before {
        width: calc(var(--wf) * 0.5 + 20px);
        /*transform: translate(40px, -21px);*/
        transform: translate(calc(var(--spouseNum) * 20px + 20px), -21px);
    }

    .noSpouse .node.first.last:before {
        /*transform: translate(20px, -21px);*/
    }

    .node.first.last:after {
        top: 0;
        content: '';
        width: calc(var(--wf) * 0.5 + 20px);
        height: 20px;
        background: var(--bg);
        position: absolute;
        transform: translate(-19px, -21px);
        right: 0;
    }

    .noSpouse .node.first.last:after {
        /*transform: translate(-40px, -21px);*/
    }

    .male {
        background-color: var(--mbg);
        border: 1px solid var(--mline);
    }

    .male i {
        color: var(--mline);
    }

    .female {
        background-color: var(--fbg);
        border: 1px solid var(--fline);
    }

    .female i {
        color: var(--fline);
    }


    .death {
        border-color: var(--deathline);
        background: var(--deathbg);
    }

    .death i, .death span {
        opacity: .3;
    }

    .node-content {
        display: flex;
        flex-direction: column;
        align-items: center;
        height: 100%;
    }

    .node-content i {
        font-size: 32px;
        width: 32px;
        height: 32px;
    }

    .node-content i.tx {
        margin-top: 3px;
        border-radius: 8px;
        overflow: hidden;
    }

    .node-content i img {
        width: 100%;
        height: 100%;
        object-fit: cover;
    }

    .node-content span {
        height: calc(100% - 32px);
        font-size: 18px;
        width: 18px;
        line-height: 1em;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: 400;
    }


    .children {
        display: flex;
        /*justify-content: center;*/
        position: relative;
        gap: 15px;
    }

    .children:before {
        content: '';
        position: absolute;
        top: -20px;
        left: 0px;
        width: 100%;
        height: 1px;
        background-color: var(--line);
    }


    @media (max-width: 768px) {

    }
</style>
